import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import API from '../api/axios'; // Siguraduhing tama ang path ng axios mo

function PostPage() {
  const { id } = useParams(); // Kukuha ng :id mula sa URL
  const [post, setPost] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const { data } = await API.get(`/posts/${id}`);
        setPost(data);
      } catch (err) {
        setError('Hindi mahanap ang post na ito. 😅');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  if (loading) return <div className="loading">Loading post... ⏳</div>;
  if (error) return <div className="error-msg">{error}</div>;
  if (!post) return <div>Post not found.</div>;

  return (
    <div className="post-detail-container" style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
      {post.image && (
        <img 
          src={post.image} 
          alt={post.title} 
          style={{ width: '100%', borderRadius: '15px', marginBottom: '1rem' }} 
        />
      )}
      
      <h1>{post.title}</h1>
      <p className="post-meta" style={{ color: '#666', fontSize: '0.9rem' }}>
        Published on: {new Date(post.createdAt).toLocaleDateString()}
      </p>
      
      <hr />
      
      <div className="post-body" style={{ lineHeight: '1.6', fontSize: '1.1rem', marginTop: '1.5rem' }}>
        {post.body}
      </div>
      
      <button 
        onClick={() => window.history.back()} 
        style={{ marginTop: '2rem', padding: '10px 20px', cursor: 'pointer' }}
      >
        ⬅️ Back to Home
      </button>
    </div>
  );
}

// ITO ANG PINAKA-IMPORTANTE! Huwag kalimutan:
export default PostPage;
